class Dog:
    species = "Canis familiaris"  # class attribute (shared)

    def __init__(self, name, age):
        self.name = name          # instance attribute
        self.age = age

    def speak(self):
        return f"{self.name} says Woof!"

    def __repr__(self):
        return f"Dog(name={self.name!r}, age={self.age})"

    def __str__(self):
        return f"{self.name} ({self.age} years old)"


rex = Dog("Rex", 4)
print(rex.speak())   # Rex says Woof!
print(repr(rex))     # Dog(name='Rex', age=4)
print(str(rex))      # Rex (4 years old)
print(Dog.species)   # Canis familiaris

class Animal:
    def __init__(self, name):
        self.name = name

    def speak(self):
        raise NotImplementedError("Subclass must implement speak()")

    def __str__(self):
        return f"{self.__class__.__name__}({self.name})"


class Dog(Animal):
    def speak(self):
        return f"{self.name} says Woof!"


class Cat(Animal):
    def speak(self):
        return f"{self.name} says Meow!"


animals = [Dog("Rex"), Cat("Whiskers"), Dog("Buddy")]
for animal in animals:
    print(animal.speak())

print(isinstance(animals[0], Animal))  # True
print(isinstance(animals[0], Dog))     # True
print(isinstance(animals[0], Cat))     # False

# Basic try/except/finally
def divide(a, b):
    try:
        result = a / b
    except ZeroDivisionError:
        print("Cannot divide by zero")
        return None
    else:
        print("Success")
        return result
    finally:
        print("divide() finished")  # always runs

print(divide(10, 2))  # Success / 5.0
print(divide(10, 0))  # Cannot divide by zero / None

# Multiple exception types
def parse_int(value):
    try:
        return int(value)
    except (ValueError, TypeError) as e:
        print(f"Could not parse: {e}")
        return 0

# Raise custom exceptions
class InsufficientFundsError(Exception):
    pass

def withdraw(balance, amount):
    if amount > balance:
        raise InsufficientFundsError(f"Need {amount}, have {balance}")
    return balance - amount

import functools
import time

# A simple decorator
def timer(func):
    @functools.wraps(func)
    def wrapper(*args, **kwargs):
        start = time.perf_counter()
        result = func(*args, **kwargs)
        elapsed = time.perf_counter() - start
        print(f"{func.__name__} took {elapsed:.4f}s")
        return result
    return wrapper


@timer
def slow_sum(n):
    return sum(range(n))


print(slow_sum(1_000_000))
# slow_sum took 0.0312s
# 499999500000

# Built-in: memoization
from functools import lru_cache

@lru_cache(maxsize=None)
def fibonacci(n):
    if n < 2:
        return n
    return fibonacci(n - 1) + fibonacci(n - 2)

print(fibonacci(50))  # instant

from typing import Optional

# Basic annotations
def greet(name: str, times: int = 1) -> str:
    return (name + "! ") * times


# Optional parameter (may be None)
def find_user(user_id: int) -> Optional[str]:
    users = {1: "Alice", 2: "Bob"}
    return users.get(user_id)


# Collections
def average(numbers: list[float]) -> float:
    return sum(numbers) / len(numbers)


# Python 3.10+ union syntax
def process(value: int | str) -> str:
    return str(value)


print(greet("Alice", 2))      # Alice! Alice!
print(find_user(1))           # Alice
print(find_user(99))          # None
